import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.C00B0EYs.js";const u=JSON.parse('{"title":"FAQ","description":"Common questions about file formats, limits, and current behavior.","frontmatter":{"title":"FAQ","description":"Common questions about file formats, limits, and current behavior."},"headers":[],"relativePath":"docs/guide/faq.md","filePath":"docs/guide/faq.md"}'),o={name:"docs/guide/faq.md"};function s(n,e,d,c,h,l){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-is-msep" tabindex="-1">What is <code>.msep</code>? <a class="header-anchor" href="#what-is-msep" aria-label="Permalink to &quot;What is `.msep`?&quot;">​</a></h2><p><code>.msep</code> is the editable project container used by Motor Sound Editor. It packages project metadata, track definitions, curve data, and referenced audio together so the whole project can be reopened or moved as one unit.</p><h2 id="which-audio-formats-can-i-assign-to-tracks" tabindex="-1">Which audio formats can I assign to tracks? <a class="header-anchor" href="#which-audio-formats-can-i-assign-to-tracks" aria-label="Permalink to &quot;Which audio formats can I assign to tracks?&quot;">​</a></h2><p>The current version supports:</p><ul><li><code>wav</code></li><li><code>ogg</code></li></ul><h2 id="why-does-the-interface-show-traction-coasting-and-brake-if-only-traction-and-brake-curves-are-editable" tabindex="-1">Why does the interface show traction, coasting, and brake if only traction and brake curves are editable? <a class="header-anchor" href="#why-does-the-interface-show-traction-coasting-and-brake-if-only-traction-and-brake-curves-are-editable" aria-label="Permalink to &quot;Why does the interface show traction, coasting, and brake if only traction and brake curves are editable?&quot;">​</a></h2><p>The preview system exposes three simulator states, but the current authoring model stores only dedicated traction and brake curve sets. In the current version, coasting still previews through the traction-side curves.</p><h2 id="can-i-preview-multiple-tracks-at-the-same-time" tabindex="-1">Can I preview multiple tracks at the same time? <a class="header-anchor" href="#can-i-preview-multiple-tracks-at-the-same-time" aria-label="Permalink to &quot;Can I preview multiple tracks at the same time?&quot;">​</a></h2><p>Yes. As long as a track is audible and has valid audio assigned, the preview engine can play multiple layers together.</p><h2 id="are-hidden-tracks-still-audible" tabindex="-1">Are hidden tracks still audible? <a class="header-anchor" href="#are-hidden-tracks-still-audible" aria-label="Permalink to &quot;Are hidden tracks still audible?&quot;">​</a></h2><p>No. In the current implementation, preview uses only tracks that are enabled, unmuted, and not hidden.</p><h2 id="if-i-replace-a-track-s-audio-does-the-old-file-stay-in-the-project-forever" tabindex="-1">If I replace a track&#39;s audio, does the old file stay in the project forever? <a class="header-anchor" href="#if-i-replace-a-track-s-audio-does-the-old-file-stay-in-the-project-forever" aria-label="Permalink to &quot;If I replace a track&#39;s audio, does the old file stay in the project forever?&quot;">​</a></h2><p>No. Save and Save As clean up unreferenced audio, so replaced files do not keep accumulating inside the <code>.msep</code> project.</p><h2 id="is-there-a-finished-settings-page" tabindex="-1">Is there a finished settings page? <a class="header-anchor" href="#is-there-a-finished-settings-page" aria-label="Permalink to &quot;Is there a finished settings page?&quot;">​</a></h2><p>No. The codebase already has settings storage, but the current user-facing build does not include a finished settings screen.</p><h2 id="which-export-targets-work-right-now" tabindex="-1">Which export targets work right now? <a class="header-anchor" href="#which-export-targets-work-right-now" aria-label="Permalink to &quot;Which export targets work right now?&quot;">​</a></h2><p>In the current export dialog, only BVE is available. Other targets are visible but cannot be selected.</p><h2 id="can-i-rely-on-export-output-only-and-skip-saving-the-msep-file" tabindex="-1">Can I rely on export output only and skip saving the <code>.msep</code> file? <a class="header-anchor" href="#can-i-rely-on-export-output-only-and-skip-saving-the-msep-file" aria-label="Permalink to &quot;Can I rely on export output only and skip saving the `.msep` file?&quot;">​</a></h2><p>That is not recommended. <code>.msep</code> is the editable source project, while the export package is the delivery artifact. One does not replace the other.</p>',20)])])}const f=a(o,[["render",s]]);export{u as __pageData,f as default};
